svg.script:
var BASE = 'https://statevec.com';
var THEME = {
  bg: '#0f1419', panel: '#1a1f2e', border: '#2a3040', header: '#003366',
  text: '#e8e8e8', muted: '#8899aa',
  red: '#CC0000', blue: '#126BD9', sand: '#D4B98B', green: '#4ade80',
  redDark: '#660000', textOnRed: '#ffffff', textOnBlue: '#ffffff'
};
try {
  var cs = getComputedStyle(document.documentElement);
  var props = ['bg','panel','border','header','text','text-muted','red','blue','sand','green','red-dark','text-on-red','text-on-blue'];
  var jsKeys = ['bg','panel','border','header','text','muted','red','blue','sand','green','redDark','textOnRed','textOnBlue'];
  for (var ti = 0; ti < props.length; ti++) {
    var v = cs.getPropertyValue('--' + props[ti]).trim();
    if (v) THEME[jsKeys[ti]] = v;
  }
} catch(e) {}
var ns = 'http://www.w3.org/2000/svg';

/* ── Hashes (read-only) ── */
var HASHES = {
  state:    '2cb87f5f6c4c76da45361c4f934bee8e3d2ed29f0439fc35fbc1ae1727059be9',
  checkins: 'a0c0e74f772b453b6e0352781490c9ac4dfdc781af90b4b3f24b667557c1d4e1',
  votes:    '802e1abbe632e0612827bb2a79e8bc892a90e1b6188550cc587d0e3139763a10',
  questions:'02039b6bc9f648e1ddb26a3b3d1c192c210f68fc624ad875ea2c45974f855dfc',
  comments: 'f28f9c8c5d9344c36a685ebc3817b445b16d76ae1eea257514362d953a36e2e6',
  tables:   '4a5392639292738bfc5c0b250f822de569a507d9dcdcfb6cbd97f50ad471160c'
};

/* ── Tension definitions ── */
var TENSIONS = [
  { id: 'tension0', title: 'Cognitive Offloading vs. Deep Learning',
    left: 'Cognitive offloading', right: 'Deep learning',
    leftDesc: 'AI handles routine tasks, freeing cognitive load',
    rightDesc: 'Students must struggle to truly understand' },
  { id: 'tension1', title: 'Personalization vs. Belonging',
    left: 'Personalization', right: 'Belonging',
    leftDesc: 'Tailored AI paths for each learner',
    rightDesc: 'Shared experience builds community' },
  { id: 'tension2', title: 'Assistance vs. Authorship',
    left: 'Assistance', right: 'Authorship',
    leftDesc: 'AI as a helpful collaborator',
    rightDesc: 'Student owns original thought' },
  { id: 'tension3', title: 'Innovation vs. Governance',
    left: 'Innovation', right: 'Governance',
    leftDesc: 'Move fast, explore new tools',
    rightDesc: 'Policies and guardrails first' }
];

/* ── Cached state ── */
var state = {};
var checkins = {};
var votes = {};
var questions = {};
var comments = {};
var tables = {};
var currentPhase = '';
var currentTensionIdx = -1;

/* ── Voting countdown state ── */
var VOTING_DURATION = 60;
var votingCountdownInterval = null;
var lastVotingOpen = false;
var votingOpenedAtLocal = 0;

/* ── DOM refs ── */
var connDot = document.getElementById('connDot');
var topParticipants = document.getElementById('topParticipants');
var statusText = document.getElementById('statusText');
var phaseLabel = document.getElementById('phaseLabel');
var clockText = document.getElementById('clockText');

var phaseCheckin = document.getElementById('phaseCheckin');
var phaseTension = document.getElementById('phaseTension');
var phaseResults = document.getElementById('phaseResults');

var checkinCount = document.getElementById('checkinCount');
var nameGrid = document.getElementById('nameGrid');

var tensionTitle = document.getElementById('tensionTitle');
var voteDots = document.getElementById('voteDots');
var meanIndicator = document.getElementById('meanIndicator');
var meanLabel = document.getElementById('meanLabel');
var poleLeft = document.getElementById('poleLeft');
var poleRight = document.getElementById('poleRight');
var poleMiddle = document.getElementById('poleMiddle');
var voteSummary = document.getElementById('voteSummary');
var tensionPoleALabel = document.getElementById('tensionPoleALabel');
var tensionPoleBLabel = document.getElementById('tensionPoleBLabel');
var tensionPoleADesc = document.getElementById('tensionPoleADesc');
var tensionPoleBDesc = document.getElementById('tensionPoleBDesc');
var questionCount = document.getElementById('questionCount');
var commentCount = document.getElementById('commentCount');
var questionsList = document.getElementById('questionsList');
var commentsList = document.getElementById('commentsList');
var countdownTimer = document.getElementById('countdownTimer');
var countdownLabel = document.getElementById('countdownLabel');

/* Revote DOM refs */
var initialVotesLabel = document.getElementById('initialVotesLabel');
var revoteLabel = document.getElementById('revoteLabel');
var revoteSpectrumBg = document.getElementById('revoteSpectrumBg');
var revoteSpectrumGrad = document.getElementById('revoteSpectrumGrad');
var revoteDots = document.getElementById('revoteDots');
var revoteMeanIndicator = document.getElementById('revoteMeanIndicator');
var revoteMeanLabel = document.getElementById('revoteMeanLabel');
var shiftArrowGroup = document.getElementById('shiftArrowGroup');
var shiftArrowLine = document.getElementById('shiftArrowLine');
var shiftArrowHead = document.getElementById('shiftArrowHead');
var shiftText = document.getElementById('shiftText');

/* Table notes DOM refs */
var tableNotesSection = document.getElementById('tableNotesSection');
var tableNotesList = document.getElementById('tableNotesList');

/* Description box refs for repositioning */
var tensionPoleABox = document.getElementById('tensionPoleABox');
var tensionPoleBBox = document.getElementById('tensionPoleBBox');

/* ── Helpers ── */
function clearChildren(el) {
  while (el.firstChild) el.removeChild(el.firstChild);
}

function truncate(str, max) {
  if (!str) return '';
  return str.length > max ? str.substring(0, max) + '...' : str;
}

function updateClock() {
  var d = new Date();
  var h = d.getHours();
  var m = d.getMinutes();
  var s = d.getSeconds();
  clockText.textContent =
    (h < 10 ? '0' : '') + h + ':' +
    (m < 10 ? '0' : '') + m + ':' +
    (s < 10 ? '0' : '') + s;
}
setInterval(updateClock, 1000);
updateClock();

/* ── Extract vote list for a tension index ── */
/* Flat keys: 'tension0:userId' = voteValue at top level */
function getVotesForTension(tIdx) {
  var prefix = 'tension' + tIdx + ':';
  var voteList = [];
  var val = votes.val || votes;
  if (!val || typeof val !== 'object') return voteList;

  var allKeys = Object.keys(val);
  for (var i = 0; i < allKeys.length; i++) {
    if (allKeys[i].indexOf(prefix) === 0) {
      var v = val[allKeys[i]];
      if (typeof v === 'number') {
        voteList.push(v);
      }
    }
  }
  return voteList;
}

/* ── Extract revote list for a tension index ── */
/* Flat keys: 'revote0:userId' = voteValue at top level */
function getRevotesForTension(tIdx) {
  var prefix = 'revote' + tIdx + ':';
  var voteList = [];
  var val = votes.val || votes;
  if (!val || typeof val !== 'object') return voteList;

  var allKeys = Object.keys(val);
  for (var i = 0; i < allKeys.length; i++) {
    if (allKeys[i].indexOf(prefix) === 0) {
      var v = val[allKeys[i]];
      if (typeof v === 'number') {
        voteList.push(v);
      }
    }
  }
  return voteList;
}

/* ── Get table notes for a tension index ── */
function getTableNotes(tIdx) {
  var noteList = [];
  var val = tables.val || tables;
  if (!val || typeof val !== 'object') return noteList;

  var allKeys = Object.keys(val);
  for (var i = 0; i < allKeys.length; i++) {
    var key = allKeys[i];
    /* Match keys like 'table1:tension0', 'table2:tension0', etc. */
    var suffix = ':tension' + tIdx;
    if (key.indexOf(suffix) === key.length - suffix.length && key.indexOf('table') === 0) {
      /* Extract table number from key */
      var tableNum = key.substring(5, key.indexOf(':'));
      var noteText = val[key];
      if (typeof noteText === 'string' && noteText.length > 0) {
        noteList.push({ table: tableNum, text: noteText });
      }
    }
  }
  /* Sort by table number */
  noteList.sort(function(a, b) { return parseInt(a.table) - parseInt(b.table); });
  return noteList;
}

/* ── Compute mean for a vote list ── */
function meanOf(arr) {
  if (arr.length === 0) return 0;
  var sum = 0;
  for (var i = 0; i < arr.length; i++) sum += arr[i];
  return sum / arr.length;
}

/* ── Compute std deviation for a vote list ── */
function stdDev(arr) {
  if (arr.length < 2) return 0;
  var m = meanOf(arr);
  var sqDiffSum = 0;
  for (var j = 0; j < arr.length; j++) {
    var d = arr[j] - m;
    sqDiffSum += d * d;
  }
  return Math.sqrt(sqDiffSum / arr.length);
}

/* ── Voting countdown ── */
function startVotingCountdown() {
  votingOpenedAtLocal = Date.now();
  if (votingCountdownInterval) clearInterval(votingCountdownInterval);
  updateCountdownDisplay();
  votingCountdownInterval = setInterval(updateCountdownDisplay, 500);
}

function stopVotingCountdown() {
  if (votingCountdownInterval) {
    clearInterval(votingCountdownInterval);
    votingCountdownInterval = null;
  }
  countdownTimer.textContent = 'VOTING CLOSED';
  countdownTimer.setAttribute('visibility', 'visible');
  countdownTimer.setAttribute('fill', THEME.red);
  countdownTimer.setAttribute('font-size', '24');
  countdownLabel.setAttribute('visibility', 'hidden');
}

function updateCountdownDisplay() {
  if (!votingOpenedAtLocal) return;
  var elapsed = Math.floor((Date.now() - votingOpenedAtLocal) / 1000);
  var remaining = Math.max(0, VOTING_DURATION - elapsed);
  var mins = Math.floor(remaining / 60);
  var secs = remaining % 60;
  countdownTimer.textContent = mins + ':' + (secs < 10 ? '0' : '') + secs;
  countdownTimer.setAttribute('visibility', 'visible');
  countdownTimer.setAttribute('fill', remaining <= 10 ? THEME.red : THEME.text);
  countdownTimer.setAttribute('font-size', remaining <= 10 ? '42' : '36');
  countdownLabel.setAttribute('visibility', 'visible');
  countdownLabel.textContent = remaining > 0 ? 'voting open' : 'VOTING CLOSED';
  if (remaining <= 0) {
    countdownTimer.textContent = 'VOTING CLOSED';
    countdownTimer.setAttribute('fill', THEME.red);
    countdownTimer.setAttribute('font-size', '24');
    countdownLabel.setAttribute('visibility', 'hidden');
    if (votingCountdownInterval) {
      clearInterval(votingCountdownInterval);
      votingCountdownInterval = null;
    }
  }
}

function hideCountdown() {
  countdownTimer.setAttribute('visibility', 'hidden');
  countdownLabel.setAttribute('visibility', 'hidden');
  if (votingCountdownInterval) {
    clearInterval(votingCountdownInterval);
    votingCountdownInterval = null;
  }
}

/* ── Draw dots on a spectrum (shared helper) ── */
function drawSpectrumDots(container, voteList, spectrumWidth, color, dotRadius) {
  var posCount = {};
  for (var vi = 0; vi < voteList.length; vi++) {
    var v = Math.max(1, Math.min(5, voteList[vi]));
    var posKey = Math.round(v * 10);
    if (!posCount[posKey]) posCount[posKey] = 0;
    posCount[posKey]++;
  }

  var posDrawn = {};
  for (var vi2 = 0; vi2 < voteList.length; vi2++) {
    var vv = Math.max(1, Math.min(5, voteList[vi2]));
    var posKey2 = Math.round(vv * 10);
    if (!posDrawn[posKey2]) posDrawn[posKey2] = 0;
    var stackIdx = posDrawn[posKey2];
    posDrawn[posKey2]++;

    var cx = ((vv - 1) / 4) * spectrumWidth;
    var cy = -8 - (stackIdx * (dotRadius * 2 + 2));

    var circle = document.createElementNS(ns, 'circle');
    circle.setAttribute('cx', cx);
    circle.setAttribute('cy', cy);
    circle.setAttribute('r', dotRadius);
    circle.setAttribute('fill', color);
    circle.setAttribute('opacity', '0.8');
    circle.setAttribute('stroke', THEME.bg);
    circle.setAttribute('stroke-width', '1');
    container.appendChild(circle);
  }
}

/* ── Hide revote elements ── */
function hideRevoteElements() {
  initialVotesLabel.setAttribute('visibility', 'hidden');
  revoteLabel.setAttribute('visibility', 'hidden');
  revoteSpectrumBg.setAttribute('visibility', 'hidden');
  revoteSpectrumGrad.setAttribute('visibility', 'hidden');
  revoteMeanIndicator.setAttribute('visibility', 'hidden');
  revoteMeanLabel.setAttribute('visibility', 'hidden');
  shiftArrowGroup.setAttribute('visibility', 'hidden');
  clearChildren(revoteDots);
}

/* ── Show revote elements ── */
function showRevoteElements() {
  initialVotesLabel.setAttribute('visibility', 'visible');
  revoteLabel.setAttribute('visibility', 'visible');
  revoteSpectrumBg.setAttribute('visibility', 'visible');
  revoteSpectrumGrad.setAttribute('visibility', 'visible');
  revoteMeanIndicator.setAttribute('visibility', 'visible');
  revoteMeanLabel.setAttribute('visibility', 'visible');
  shiftArrowGroup.setAttribute('visibility', 'visible');
}

/* ── Phase switching ── */
function showPhase(phase) {
  phaseCheckin.setAttribute('visibility', phase === 'checkin' ? 'visible' : 'hidden');
  phaseTension.setAttribute('visibility', phase === 'tension' ? 'visible' : 'hidden');
  phaseResults.setAttribute('visibility', phase === 'results' ? 'visible' : 'hidden');
  currentPhase = phase;
  phaseLabel.textContent = phase ? phase.toUpperCase() : '--';
  if (phase !== 'tension') {
    hideCountdown();
  }
}

/* ── Render: Check-in phase ── */
function renderCheckin() {
  var val = checkins.val || checkins;
  var names = [];
  if (val && typeof val === 'object') {
    var keys = Object.keys(val);
    for (var i = 0; i < keys.length; i++) {
      var entry = val[keys[i]];
      if (typeof entry === 'string') {
        names.push(entry);
      } else if (entry && entry.name) {
        names.push(entry.name);
      } else if (typeof entry === 'object' && entry !== null) {
        var eKeys = Object.keys(entry);
        for (var j = 0; j < eKeys.length; j++) {
          var sub = entry[eKeys[j]];
          if (typeof sub === 'string') names.push(sub);
          else if (sub && sub.name) names.push(sub.name);
        }
      }
    }
  }

  checkinCount.textContent = names.length + ' checked in';
  topParticipants.textContent = names.length + ' participants';

  clearChildren(nameGrid);
  var cols = 8;
  var cellW = 130;
  var cellH = 24;
  for (var k = 0; k < names.length; k++) {
    var col = k % cols;
    var row = Math.floor(k / cols);
    var t = document.createElementNS(ns, 'text');
    t.setAttribute('x', col * cellW);
    t.setAttribute('y', row * cellH + 16);
    t.setAttribute('font-family', 'monospace');
    t.setAttribute('font-size', '12');
    t.setAttribute('fill', THEME.muted);
    t.textContent = truncate(names[k], 14);
    nameGrid.appendChild(t);
  }
}

/* ── Render: Tension phase ── */
function renderTension(tIdx, isVotingOpen) {
  var t = TENSIONS[tIdx];
  if (!t) return;
  currentTensionIdx = tIdx;

  tensionTitle.textContent = t.title;
  poleLeft.textContent = t.left;
  poleRight.textContent = t.right;
  tensionPoleALabel.textContent = t.left;
  tensionPoleBLabel.textContent = t.right;
  tensionPoleADesc.textContent = t.leftDesc;
  tensionPoleBDesc.textContent = t.rightDesc;

  /* Nav dots */
  for (var n = 0; n < 4; n++) {
    var dot = document.getElementById('navDot' + n);
    if (dot) {
      dot.setAttribute('fill', n === tIdx ? THEME.red : THEME.border);
    }
  }

  /* Initial votes */
  var voteList = getVotesForTension(tIdx);
  var revoteList = getRevotesForTension(tIdx);
  var hasRevotes = revoteList.length > 0;

  var SPECTRUM_W = 720;
  var total = voteList.length;
  var sum = 0;
  for (var si = 0; si < voteList.length; si++) {
    sum += Math.max(1, Math.min(5, voteList[si]));
  }

  /* Draw initial vote dots */
  clearChildren(voteDots);
  drawSpectrumDots(voteDots, voteList, SPECTRUM_W, hasRevotes ? THEME.blue : THEME.text, 6);

  /* Initial mean */
  var initialMean = total > 0 ? sum / total : 3;
  var meanX = ((initialMean - 1) / 4) * SPECTRUM_W;
  meanIndicator.setAttribute('points',
    meanX + ',122 ' + (meanX - 6) + ',134 ' + (meanX + 6) + ',134');
  meanLabel.setAttribute('x', meanX);
  meanLabel.textContent = total > 0 ? 'mean: ' + initialMean.toFixed(1) : 'mean';

  /* Handle revote display */
  if (hasRevotes) {
    showRevoteElements();

    /* Draw revote dots */
    clearChildren(revoteDots);
    drawSpectrumDots(revoteDots, revoteList, SPECTRUM_W, THEME.sand, 6);

    /* Revote mean */
    var revoteMean = meanOf(revoteList);
    var revoteMeanX = ((revoteMean - 1) / 4) * SPECTRUM_W;
    revoteMeanIndicator.setAttribute('points',
      revoteMeanX + ',204 ' + (revoteMeanX - 6) + ',216 ' + (revoteMeanX + 6) + ',216');
    revoteMeanLabel.setAttribute('x', revoteMeanX);
    revoteMeanLabel.textContent = 'mean: ' + revoteMean.toFixed(1);

    /* Shift arrow from initial mean to revote mean */
    shiftArrowLine.setAttribute('x1', meanX);
    shiftArrowLine.setAttribute('x2', revoteMeanX);
    shiftArrowHead.setAttribute('points',
      revoteMeanX + ',200 ' + (revoteMeanX - 5) + ',192 ' + (revoteMeanX + 5) + ',192');
    shiftText.textContent = 'Shift: ' + initialMean.toFixed(1) + ' \u2192 ' + revoteMean.toFixed(1);

    /* Reposition pole labels and descriptions below revote section */
    poleLeft.setAttribute('y', '260');
    poleMiddle.setAttribute('y', '260');
    poleRight.setAttribute('y', '260');
    voteSummary.setAttribute('y', '286');
    tensionPoleABox.setAttribute('y', '300');
    tensionPoleALabel.setAttribute('y', '328');
    tensionPoleADesc.setAttribute('y', '350');
    tensionPoleBBox.setAttribute('y', '300');
    tensionPoleBLabel.setAttribute('y', '328');
    tensionPoleBDesc.setAttribute('y', '350');
  } else {
    hideRevoteElements();

    /* Restore original positions */
    poleLeft.setAttribute('y', '170');
    poleMiddle.setAttribute('y', '170');
    poleRight.setAttribute('y', '170');
    voteSummary.setAttribute('y', '200');
    tensionPoleABox.setAttribute('y', '220');
    tensionPoleALabel.setAttribute('y', '248');
    tensionPoleADesc.setAttribute('y', '270');
    tensionPoleBBox.setAttribute('y', '220');
    tensionPoleBLabel.setAttribute('y', '248');
    tensionPoleBDesc.setAttribute('y', '270');
  }

  voteSummary.textContent = total + ' vote' + (total !== 1 ? 's' : '') +
    (hasRevotes ? ' / ' + revoteList.length + ' revote' + (revoteList.length !== 1 ? 's' : '') : '');
}

/* ── Render: Table Notes (shown when voting is closed) ── */
function renderTableNotes(tIdx, isVotingOpen) {
  clearChildren(tableNotesList);

  /* Only show during discussion (voting closed) */
  if (isVotingOpen) {
    tableNotesSection.setAttribute('visibility', 'hidden');
    return;
  }

  var noteList = getTableNotes(tIdx);
  if (noteList.length === 0) {
    tableNotesSection.setAttribute('visibility', 'hidden');
    return;
  }

  tableNotesSection.setAttribute('visibility', 'visible');

  for (var ni = 0; ni < noteList.length && ni < 6; ni++) {
    var note = noteList[ni];
    var y = ni * 22;

    var nt = document.createElementNS(ns, 'text');
    nt.setAttribute('x', 16);
    nt.setAttribute('y', y + 14);
    nt.setAttribute('font-family', 'monospace');
    nt.setAttribute('font-size', '14');
    nt.setAttribute('fill', THEME.text);
    nt.textContent = 'Table ' + note.table + ': ' + truncate(note.text, 40);
    tableNotesList.appendChild(nt);
  }

  /* Adjust comments section position when table notes are visible */
  var commentsY = 300 + (noteList.length * 22) + 20;
  document.getElementById('commentsHeader').setAttribute('y', commentsY);
  document.getElementById('commentsHeaderText').setAttribute('y', commentsY + 22);
  commentCount.setAttribute('y', commentsY + 22);
  commentsList.setAttribute('transform', 'translate(0, ' + (commentsY + 40) + ')');
}

/* ── Reset comments position when table notes hidden ── */
function resetCommentsPosition() {
  document.getElementById('commentsHeader').setAttribute('y', '320');
  document.getElementById('commentsHeaderText').setAttribute('y', '342');
  commentCount.setAttribute('y', '342');
  commentsList.setAttribute('transform', 'translate(0, 360)');
}

/* ── Render: Questions ── */
function renderQuestions(tIdx) {
  clearChildren(questionsList);
  var val = questions.val || questions;
  var qList = [];

  if (val && typeof val === 'object') {
    var keys = Object.keys(val);
    for (var i = 0; i < keys.length; i++) {
      var q = val[keys[i]];
      if (q && typeof q === 'object') {
        if (typeof q.tension === 'number' && q.tension === tIdx) {
          var upvotes = 0;
          var upPrefix = 'upvote:' + keys[i] + ':';
          for (var ui = 0; ui < keys.length; ui++) {
            if (keys[ui].indexOf(upPrefix) === 0 && val[keys[ui]]) upvotes++;
          }
          qList.push({
            text: q.text || keys[i],
            upvotes: upvotes,
            highlighted: q.highlighted || false,
            name: q.author || 'anonymous'
          });
        }
      }
    }
  }

  qList.sort(function(a, b) { return b.upvotes - a.upvotes; });
  var top5 = qList.slice(0, 5);

  questionCount.textContent = qList.length + '';

  for (var qi = 0; qi < top5.length; qi++) {
    var q2 = top5[qi];
    var y = qi * 44;

    var bg = document.createElementNS(ns, 'rect');
    bg.setAttribute('x', 0);
    bg.setAttribute('y', y);
    bg.setAttribute('width', 472);
    bg.setAttribute('height', 40);
    bg.setAttribute('rx', 6);
    bg.setAttribute('fill', THEME.panel);
    bg.setAttribute('stroke', q2.highlighted ? THEME.red : THEME.border);
    bg.setAttribute('stroke-width', q2.highlighted ? '2' : '1');
    questionsList.appendChild(bg);

    if (q2.highlighted) {
      var star = document.createElementNS(ns, 'text');
      star.setAttribute('x', 12);
      star.setAttribute('y', y + 22);
      star.setAttribute('font-family', 'monospace');
      star.setAttribute('font-size', '14');
      star.setAttribute('fill', THEME.red);
      star.textContent = '\u2605';
      questionsList.appendChild(star);
    }

    var qt = document.createElementNS(ns, 'text');
    qt.setAttribute('x', q2.highlighted ? 34 : 12);
    qt.setAttribute('y', y + 18);
    qt.setAttribute('font-family', 'monospace');
    qt.setAttribute('font-size', '14');
    qt.setAttribute('fill', THEME.text);
    qt.textContent = truncate(q2.text, 42);
    questionsList.appendChild(qt);

    var qa = document.createElementNS(ns, 'text');
    qa.setAttribute('x', q2.highlighted ? 34 : 12);
    qa.setAttribute('y', y + 34);
    qa.setAttribute('font-family', 'monospace');
    qa.setAttribute('font-size', '10');
    qa.setAttribute('fill', THEME.muted);
    qa.textContent = q2.name;
    questionsList.appendChild(qa);

    var uv = document.createElementNS(ns, 'text');
    uv.setAttribute('x', 456);
    uv.setAttribute('y', y + 22);
    uv.setAttribute('font-family', 'monospace');
    uv.setAttribute('font-size', '13');
    uv.setAttribute('fill', THEME.sand);
    uv.setAttribute('text-anchor', 'end');
    uv.textContent = '\u25B2 ' + q2.upvotes;
    questionsList.appendChild(uv);
  }
}

/* ── Render: Comments ── */
function renderComments(tIdx) {
  clearChildren(commentsList);
  var val = comments.val || comments;
  var cList = [];

  if (val && typeof val === 'object') {
    var keys = Object.keys(val);
    for (var i = 0; i < keys.length; i++) {
      var c = val[keys[i]];
      if (c && typeof c === 'object') {
        if (typeof c.tension === 'number' && c.tension === tIdx) {
          cList.push({
            text: c.text || c.msg || c.comment || '',
            name: c.author || c.name || 'anonymous',
            ts: c.t || c.ts || c.time || 0
          });
        }
      }
    }
  }

  cList.sort(function(a, b) { return b.ts - a.ts; });
  var last4 = cList.slice(0, 4);

  commentCount.textContent = cList.length + '';

  for (var ci = 0; ci < last4.length; ci++) {
    var c2 = last4[ci];
    var y = ci * 56;

    var bg = document.createElementNS(ns, 'rect');
    bg.setAttribute('x', 0);
    bg.setAttribute('y', y);
    bg.setAttribute('width', 472);
    bg.setAttribute('height', 50);
    bg.setAttribute('rx', 6);
    bg.setAttribute('fill', THEME.panel);
    bg.setAttribute('stroke', THEME.border);
    commentsList.appendChild(bg);

    var cn = document.createElementNS(ns, 'text');
    cn.setAttribute('x', 12);
    cn.setAttribute('y', y + 20);
    cn.setAttribute('font-family', 'monospace');
    cn.setAttribute('font-size', '12');
    cn.setAttribute('fill', THEME.sand);
    cn.textContent = c2.name;
    commentsList.appendChild(cn);

    var ct = document.createElementNS(ns, 'text');
    ct.setAttribute('x', 12);
    ct.setAttribute('y', y + 40);
    ct.setAttribute('font-family', 'monospace');
    ct.setAttribute('font-size', '14');
    ct.setAttribute('fill', THEME.text);
    ct.textContent = truncate(c2.text, 46);
    commentsList.appendChild(ct);
  }
}

/* ── Render: Results phase (richer narrative synthesis) ── */
function renderResults() {
  var totalQ = 0;
  var totalC = 0;
  var totalP = 0;

  /* Count participants from checkins */
  var cVal = checkins.val || checkins;
  if (cVal && typeof cVal === 'object') {
    totalP = Object.keys(cVal).length;
  }
  topParticipants.textContent = totalP + ' participants';

  /* Count questions and find top question across all tensions */
  var qVal = questions.val || questions;
  var bestQuestionText = '';
  var bestQuestionUpvotes = -1;

  if (qVal && typeof qVal === 'object') {
    var qKeys = Object.keys(qVal);
    for (var qi3 = 0; qi3 < qKeys.length; qi3++) {
      var qq3 = qVal[qKeys[qi3]];
      if (qq3 && typeof qq3 === 'object' && qq3.text) {
        totalQ++;
        /* Count upvotes */
        var ups3 = 0;
        var upPfx3 = 'upvote:' + qKeys[qi3] + ':';
        for (var upk3 = 0; upk3 < qKeys.length; upk3++) {
          if (qKeys[upk3].indexOf(upPfx3) === 0 && qVal[qKeys[upk3]]) ups3++;
        }
        if (ups3 > bestQuestionUpvotes) {
          bestQuestionUpvotes = ups3;
          bestQuestionText = qq3.text;
        }
      }
    }
  }

  /* Count comments */
  var cmVal = comments.val || comments;
  if (cmVal && typeof cmVal === 'object') {
    var cmKeys = Object.keys(cmVal);
    for (var ci2 = 0; ci2 < cmKeys.length; ci2++) {
      var cm = cmVal[cmKeys[ci2]];
      if (cm && typeof cm === 'object' && cm.text) totalC++;
    }
  }

  /* Stats line */
  document.getElementById('resultStatsLine').textContent =
    totalP + ' participants \u2022 ' + totalQ + ' questions \u2022 ' + totalC + ' comments';

  /* Collect stats for all tensions */
  var allStdDevs = [];
  var allMeans = [];
  var allRevoteMeans = [];
  var allVoteCounts = [];
  var allRevoteCounts = [];
  var allShifts = [];

  /* Mini spectrum for each tension */
  for (var ti = 0; ti < 4; ti++) {
    var tDef = TENSIONS[ti];
    document.getElementById('resultTitle' + ti).textContent = tDef.title;
    document.getElementById('resultSub' + ti).textContent = tDef.left + ' vs. ' + tDef.right;
    document.getElementById('resultLeftLabel' + ti).textContent = tDef.left;
    document.getElementById('resultRightLabel' + ti).textContent = tDef.right;

    var vList = getVotesForTension(ti);
    var rList = getRevotesForTension(ti);

    document.getElementById('resultVotes' + ti).textContent = vList.length + ' votes' +
      (rList.length > 0 ? ' / ' + rList.length + ' revotes' : '');
    allVoteCounts.push(vList.length);
    allRevoteCounts.push(rList.length);

    /* Draw initial dots (blue) */
    var dotsG = document.getElementById('resultDots' + ti);
    clearChildren(dotsG);

    var miniW = 240;
    var posCount = {};
    var vSum = 0;
    for (var k = 0; k < vList.length; k++) {
      var vv = Math.max(1, Math.min(5, vList[k]));
      vSum += vv;
      var pk = Math.round(vv * 10);
      if (!posCount[pk]) posCount[pk] = 0;
      posCount[pk]++;
    }

    var posDrawn = {};
    for (var k2 = 0; k2 < vList.length; k2++) {
      var vv2 = Math.max(1, Math.min(5, vList[k2]));
      var pk2 = Math.round(vv2 * 10);
      if (!posDrawn[pk2]) posDrawn[pk2] = 0;
      var si2 = posDrawn[pk2];
      posDrawn[pk2]++;

      var cx = ((vv2 - 1) / 4) * miniW;
      var cy = -4 - (si2 * 8);

      var circle = document.createElementNS(ns, 'circle');
      circle.setAttribute('cx', cx);
      circle.setAttribute('cy', cy);
      circle.setAttribute('r', 3);
      circle.setAttribute('fill', rList.length > 0 ? THEME.blue : THEME.text);
      circle.setAttribute('opacity', '0.8');
      circle.setAttribute('stroke', THEME.bg);
      circle.setAttribute('stroke-width', '1');
      dotsG.appendChild(circle);
    }

    var iMean = vList.length > 0 ? vSum / vList.length : 3;
    var sd = stdDev(vList);
    allMeans.push(iMean);
    allStdDevs.push(sd);

    document.getElementById('resultMean' + ti).textContent = vList.length > 0 ? 'mean: ' + iMean.toFixed(1) : 'mean: --';
    document.getElementById('resultStdDev' + ti).textContent = vList.length > 0 ? 'std dev: ' + sd.toFixed(2) : 'std dev: --';

    /* Draw revote dots (gold) if revote data exists */
    var revoteDotsG = document.getElementById('resultRevoteDots' + ti);
    clearChildren(revoteDotsG);

    if (rList.length > 0) {
      /* Show revote elements */
      document.getElementById('resultRevoteLabel' + ti).setAttribute('visibility', 'visible');
      document.getElementById('resultRevoteBg' + ti).setAttribute('visibility', 'visible');

      var rPosCount = {};
      var rSum = 0;
      for (var rk = 0; rk < rList.length; rk++) {
        var rv = Math.max(1, Math.min(5, rList[rk]));
        rSum += rv;
        var rpk = Math.round(rv * 10);
        if (!rPosCount[rpk]) rPosCount[rpk] = 0;
        rPosCount[rpk]++;
      }

      var rPosDrawn = {};
      for (var rk2 = 0; rk2 < rList.length; rk2++) {
        var rv2 = Math.max(1, Math.min(5, rList[rk2]));
        var rpk2 = Math.round(rv2 * 10);
        if (!rPosDrawn[rpk2]) rPosDrawn[rpk2] = 0;
        var rsi = rPosDrawn[rpk2];
        rPosDrawn[rpk2]++;

        var rcx = ((rv2 - 1) / 4) * miniW;
        var rcy = -4 - (rsi * 8);

        var rCircle = document.createElementNS(ns, 'circle');
        rCircle.setAttribute('cx', rcx);
        rCircle.setAttribute('cy', rcy);
        rCircle.setAttribute('r', 3);
        rCircle.setAttribute('fill', THEME.sand);
        rCircle.setAttribute('opacity', '0.8');
        rCircle.setAttribute('stroke', THEME.bg);
        rCircle.setAttribute('stroke-width', '1');
        revoteDotsG.appendChild(rCircle);
      }

      var rMean = rSum / rList.length;
      allRevoteMeans.push(rMean);

      /* Shift arrow for mini chart */
      var shiftArrowG = document.getElementById('resultShiftArrow' + ti);
      var iMeanX = 20 + ((iMean - 1) / 4) * miniW;
      var rMeanX = 20 + ((rMean - 1) / 4) * miniW;
      shiftArrowG.setAttribute('visibility', 'visible');
      document.getElementById('resultShiftLine' + ti).setAttribute('x1', iMeanX);
      document.getElementById('resultShiftLine' + ti).setAttribute('x2', rMeanX);
      document.getElementById('resultShiftHead' + ti).setAttribute('points',
        rMeanX + ',92 ' + (rMeanX - 3) + ',86 ' + (rMeanX + 3) + ',86');

      var shiftDist = Math.abs(rMean - iMean);
      allShifts.push({ idx: ti, shift: shiftDist, from: iMean, to: rMean });
      document.getElementById('resultShiftText' + ti).textContent =
        iMean.toFixed(1) + ' \u2192 ' + rMean.toFixed(1);
    } else {
      document.getElementById('resultRevoteLabel' + ti).setAttribute('visibility', 'hidden');
      document.getElementById('resultRevoteBg' + ti).setAttribute('visibility', 'hidden');
      document.getElementById('resultShiftArrow' + ti).setAttribute('visibility', 'hidden');
      document.getElementById('resultShiftText' + ti).textContent = '';
      allRevoteMeans.push(null);
    }
  }

  /* ── Narrative stats ── */
  /* 1. Most Divided */
  var mostDividedIdx = 0;
  var maxSD = -1;
  var anyVotes = false;
  for (var sd1 = 0; sd1 < 4; sd1++) {
    if (allVoteCounts[sd1] > 0) {
      anyVotes = true;
      if (allStdDevs[sd1] > maxSD) {
        maxSD = allStdDevs[sd1];
        mostDividedIdx = sd1;
      }
    }
  }

  /* 2. Strongest Consensus */
  var strongestIdx = 0;
  var minSD = 999;
  for (var sd2 = 0; sd2 < 4; sd2++) {
    if (allVoteCounts[sd2] > 0) {
      if (allStdDevs[sd2] < minSD) {
        minSD = allStdDevs[sd2];
        strongestIdx = sd2;
      }
    }
  }

  if (anyVotes) {
    document.getElementById('resultMostDivided').textContent =
      'The room was most divided on: ' + TENSIONS[mostDividedIdx].title + ' (spread: ' + maxSD.toFixed(1) + ')';
    document.getElementById('resultStrongestConsensus').textContent =
      'The room agreed most on: ' + TENSIONS[strongestIdx].title + ' (spread: ' + minSD.toFixed(1) + ')';
  } else {
    document.getElementById('resultMostDivided').textContent = 'The room was most divided on: no votes yet';
    document.getElementById('resultStrongestConsensus').textContent = 'The room agreed most on: no votes yet';
  }

  /* 3. Biggest Shift */
  if (allShifts.length > 0) {
    allShifts.sort(function(a, b) { return b.shift - a.shift; });
    var biggest = allShifts[0];
    document.getElementById('resultBiggestShift').textContent =
      'Minds changed most on: ' + TENSIONS[biggest.idx].title +
      ' (' + biggest.from.toFixed(1) + ' \u2192 ' + biggest.to.toFixed(1) + ')';
  } else {
    document.getElementById('resultBiggestShift').textContent = 'No revote data yet';
  }

  /* 4. Question of the Night */
  if (bestQuestionText) {
    document.getElementById('resultTopQuestion').textContent =
      '"' + truncate(bestQuestionText, 50) + '" (' + bestQuestionUpvotes + ' upvotes)';
  } else {
    document.getElementById('resultTopQuestion').textContent = 'No questions submitted';
  }
}

/* ── Fetch helper ── */
function fetchHash(hash) {
  return fetch(BASE + '/v/' + hash).then(function(r) {
    if (r.ok) return r.json();
    return null;
  }).catch(function() { return null; });
}

/* ── Main poll ── */
function poll() {
  var fetches = [
    fetchHash(HASHES.state),
    fetchHash(HASHES.checkins),
    fetchHash(HASHES.votes),
    fetchHash(HASHES.questions),
    fetchHash(HASHES.comments),
    fetchHash(HASHES.tables)
  ];

  Promise.all(fetches).then(function(results) {
    var stateData = results[0];
    var checkinsData = results[1];
    var votesData = results[2];
    var questionsData = results[3];
    var commentsData = results[4];
    var tablesData = results[5];

    connDot.setAttribute('fill', THEME.green);
    statusText.textContent = 'connected | last poll: ' + new Date().toLocaleTimeString();

    if (stateData && stateData.val) state = stateData.val;
    if (checkinsData && checkinsData.val) checkins = { val: checkinsData.val };
    else if (checkinsData) checkins = checkinsData;
    if (votesData && votesData.val) votes = { val: votesData.val };
    else if (votesData) votes = votesData;
    if (questionsData && questionsData.val) questions = { val: questionsData.val };
    else if (questionsData) questions = questionsData;
    if (commentsData && commentsData.val) comments = { val: commentsData.val };
    else if (commentsData) comments = commentsData;
    if (tablesData && tablesData.val) tables = { val: tablesData.val };
    else if (tablesData) tables = tablesData;

    /* Determine phase */
    var phase = 'checkin';
    if (state && state.phase) {
      phase = state.phase;
    }

    /* Determine tension index */
    var tIdx = 0;
    if (state && typeof state.currentTension === 'number') {
      tIdx = state.currentTension;
    }

    /* Handle voting countdown */
    var isVotingOpen = !!(state && state.votingOpen);
    if (isVotingOpen && !lastVotingOpen) {
      startVotingCountdown();
    } else if (!isVotingOpen && lastVotingOpen) {
      stopVotingCountdown();
    } else if (!isVotingOpen && !lastVotingOpen && phase === 'tension') {
      if (!votingOpenedAtLocal) {
        hideCountdown();
      }
    }
    lastVotingOpen = isVotingOpen;

    /* Update participant count */
    var cVal2 = checkins.val || checkins;
    var pCount = 0;
    if (cVal2 && typeof cVal2 === 'object') {
      pCount = Object.keys(cVal2).length;
    }
    topParticipants.textContent = pCount + ' participants';

    /* Show appropriate phase */
    showPhase(phase);

    if (phase === 'checkin') {
      renderCheckin();
    } else if (phase === 'tension') {
      renderTension(tIdx, isVotingOpen);
      renderQuestions(tIdx);
      renderTableNotes(tIdx, isVotingOpen);
      if (!isVotingOpen && getTableNotes(tIdx).length > 0) {
        /* Comments position was adjusted by renderTableNotes */
      } else {
        resetCommentsPosition();
      }
      renderComments(tIdx);
    } else if (phase === 'results') {
      renderResults();
    }

  }).catch(function(err) {
    connDot.setAttribute('fill', THEME.red);
    statusText.textContent = 'error: ' + (err.message || 'poll failed');
  });
}

/* ── Init ── */
showPhase('checkin');
poll();
setInterval(poll, 2000);
